const ratio = Math.min(imageW / containerW, imageH / containerH);
if (ratio < 2) return 1;
// floor(log2(ratio)) via clz32 — ratio >= 2 here so (ratio|0) >= 2
const log2 = 31 - Math.clz32(ratio | 0);
return (1 << Math.min(log2, 3)) as Downsample;

